/* ── Reset & Base ── */
* { margin: 0; padding: 0; box-sizing: border-box; }

:root {
  --bg-primary: #0d1117;
  --bg-secondary: #161b22;
  --bg-tertiary: #21262d;
  --border: #30363d;
  --text-primary: #e6edf3;
  --text-secondary: #8b949e;
  --text-muted: #484f58;
  --accent: #58a6ff;
  --accent-hover: #79c0ff;
  --green: #3fb950;
  --red: #f85149;
  --yellow: #d29922;
  --diff-add-bg: #12261e;
  --diff-add-border: #1b4332;
  --diff-del-bg: #2d1215;
  --diff-del-border: #5c2127;
  --diff-hunk-bg: #1c2536;
  --sidebar-width: 280px;
}

html, body { height: 100%; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Helvetica, Arial, sans-serif; background: var(--bg-primary); color: var(--text-primary); font-size: 14px; }

#app { display: flex; flex-direction: column; height: 100vh; }

/* ── Header ── */
#header { display: flex; justify-content: space-between; align-items: center; padding: 8px 16px; background: var(--bg-secondary); border-bottom: 1px solid var(--border); flex-shrink: 0; }
.header-left { display: flex; align-items: center; gap: 12px; }
.logo { font-size: 18px; font-weight: 700; color: var(--accent); }
.subtitle { font-size: 13px; color: var(--text-secondary); }
.header-right { display: flex; align-items: center; gap: 12px; }
.tag-info { font-size: 12px; color: var(--text-secondary); }
.btn-diff { display: flex; align-items: center; gap: 4px; padding: 4px 10px; border: 1px solid var(--border); border-radius: 6px; background: var(--bg-tertiary); color: var(--text-secondary); cursor: pointer; font-size: 12px; transition: all 0.15s; }
.btn-diff:hover { border-color: var(--accent); color: var(--accent); }
.btn-diff.active { border-color: var(--yellow); color: var(--yellow); background: rgba(210, 153, 34, 0.1); }
.diff-icon { font-size: 14px; }

/* ── Main Layout ── */
#main { display: flex; flex: 1; overflow: hidden; }

/* ── Sidebar ── */
#sidebar { width: var(--sidebar-width); min-width: var(--sidebar-width); background: var(--bg-secondary); border-right: 1px solid var(--border); display: flex; flex-direction: column; overflow: hidden; }
.sidebar-header { padding: 8px; border-bottom: 1px solid var(--border); }
#search-input { width: 100%; padding: 6px 10px; background: var(--bg-tertiary); border: 1px solid var(--border); border-radius: 6px; color: var(--text-primary); font-size: 13px; outline: none; }
#search-input:focus { border-color: var(--accent); }
.file-tree { flex: 1; overflow-y: auto; padding: 4px 0; }

/* ── Tree Items ── */
.tree-item { display: flex; align-items: center; padding: 3px 8px; cursor: pointer; font-size: 13px; line-height: 1.6; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; color: var(--text-primary); transition: background 0.1s; user-select: none; }
.tree-item:hover { background: var(--bg-tertiary); }
.tree-item.active { background: rgba(88, 166, 255, 0.15); color: var(--accent); }
.tree-item.dir { color: var(--text-secondary); font-weight: 500; }
.tree-icon { width: 18px; text-align: center; margin-right: 4px; font-size: 12px; flex-shrink: 0; }
.tree-name { overflow: hidden; text-overflow: ellipsis; }
.tree-indent { flex-shrink: 0; }

/* ── Badges ── */
.badge { display: inline-block; padding: 0 5px; border-radius: 3px; font-size: 11px; font-weight: 600; margin-left: 6px; line-height: 18px; flex-shrink: 0; }
.badge-modified { background: rgba(210, 153, 34, 0.2); color: var(--yellow); }
.badge-added { background: rgba(63, 185, 80, 0.2); color: var(--green); }
.badge-deleted { background: rgba(248, 81, 73, 0.2); color: var(--red); }
.badge-renamed { background: rgba(88, 166, 255, 0.2); color: var(--accent); }

/* ── Viewer ── */
#viewer { flex: 1; display: flex; flex-direction: column; overflow: hidden; }
#viewer-header { display: flex; align-items: center; padding: 8px 16px; background: var(--bg-secondary); border-bottom: 1px solid var(--border); font-size: 13px; flex-shrink: 0; }
#file-path { color: var(--text-secondary); font-family: 'SFMono-Regular', Consolas, 'Liberation Mono', Menlo, monospace; }
.file-status { margin-left: 8px; }
#viewer-content { flex: 1; overflow-y: auto; padding: 16px; }

/* ── Welcome ── */
.welcome { max-width: 500px; margin: 80px auto; text-align: center; color: var(--text-secondary); }
.welcome h2 { color: var(--text-primary); margin-bottom: 16px; }
.welcome p { margin: 8px 0; line-height: 1.6; }

/* ── Markdown View ── */
.markdown-view { max-width: 800px; margin: 0 auto; padding: 16px; line-height: 1.7; }
.markdown-view h1, .markdown-view h2, .markdown-view h3 { margin: 24px 0 12px; border-bottom: 1px solid var(--border); padding-bottom: 6px; }
.markdown-view h1 { font-size: 28px; } .markdown-view h2 { font-size: 22px; } .markdown-view h3 { font-size: 18px; }
.markdown-view p { margin: 12px 0; }
.markdown-view code { background: var(--bg-tertiary); padding: 2px 6px; border-radius: 4px; font-size: 13px; }
.markdown-view pre { background: var(--bg-tertiary); padding: 16px; border-radius: 8px; overflow-x: auto; margin: 12px 0; }
.markdown-view pre code { background: none; padding: 0; }
.markdown-view table { border-collapse: collapse; width: 100%; margin: 12px 0; }
.markdown-view th, .markdown-view td { border: 1px solid var(--border); padding: 8px 12px; text-align: left; }
.markdown-view th { background: var(--bg-tertiary); }
.markdown-view blockquote { border-left: 4px solid var(--accent); padding-left: 16px; color: var(--text-secondary); margin: 12px 0; }
.markdown-view img { max-width: 100%; border-radius: 8px; }
.markdown-view a { color: var(--accent); text-decoration: none; }
.markdown-view a:hover { text-decoration: underline; }
.markdown-view ul, .markdown-view ol { padding-left: 24px; margin: 8px 0; }
.markdown-view li { margin: 4px 0; }

/* ── Image View ── */
.image-view { display: flex; justify-content: center; align-items: center; padding: 32px; }
.image-view img { max-width: 100%; max-height: 80vh; border-radius: 8px; box-shadow: 0 4px 16px rgba(0,0,0,0.3); }

/* ── Code View ── */
#code-view pre { margin: 0; border-radius: 8px; overflow-x: auto; }
#code-view code { font-family: 'SFMono-Regular', Consolas, 'Liberation Mono', Menlo, monospace; font-size: 13px; line-height: 1.5; }

/* ── Diff Summary ── */
.diff-summary { background: var(--bg-secondary); border: 1px solid var(--border); border-radius: 8px; padding: 12px 16px; margin-bottom: 16px; }
.diff-summary h4 { font-size: 13px; color: var(--text-secondary); margin-bottom: 8px; }
.diff-hunk { margin: 8px 0; padding: 8px 12px; border-radius: 6px; font-size: 12px; }
.diff-hunk-header { background: var(--diff-hunk-bg); color: var(--accent); padding: 4px 8px; border-radius: 4px; font-family: monospace; margin-bottom: 4px; }
.diff-hunk-reason { color: var(--text-secondary); font-style: italic; padding: 4px 8px; }

/* ── Diff Lines ── */
.diff-view { font-family: 'SFMono-Regular', Consolas, monospace; font-size: 13px; line-height: 1.5; }
.diff-line { display: flex; white-space: pre; }
.diff-line-num { width: 50px; text-align: right; padding-right: 8px; color: var(--text-muted); flex-shrink: 0; user-select: none; }
.diff-line-content { flex: 1; padding: 0 8px; }
.diff-line-add { background: var(--diff-add-bg); }
.diff-line-add .diff-line-num { color: var(--green); }
.diff-line-del { background: var(--diff-del-bg); }
.diff-line-del .diff-line-num { color: var(--red); }
.diff-line-hunk { background: var(--diff-hunk-bg); color: var(--accent); }

/* ── Scrollbar ── */
::-webkit-scrollbar { width: 8px; height: 8px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--bg-tertiary); border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: var(--text-muted); }

/* ── Dir Toggle ── */
.dir-children { overflow: hidden; }
.dir-children.collapsed { display: none; }
.tree-toggle { transition: transform 0.15s; }
.tree-toggle.collapsed { transform: rotate(-90deg); }

